library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;
use IEEE.STD_LOGIC_TEXTIO.ALL;
use std.textio.all;

entity Memory is 
    generic (
        INIT_FILE : string := "program.mem"
    );
    port (
        clk         : in  std_logic;
        we          : in  std_logic;
        re          : in  std_logic;
        address     : in  std_logic_vector(31 downto 0);
        datain      : in  std_logic_vector(31 downto 0);
        dataout     : out std_logic_vector(31 downto 0)
    );
end Memory;

architecture Behavioral of Memory is
    type mem_type is array (0 to 2**18 - 1) of std_logic_vector(31 downto 0);

    -- Function to initialize memory from file
    impure function init_mem(filename : string) return mem_type is
        file text_file : text;
        variable status : file_open_status;
        variable text_line : line;
        variable temp_bv : bit_vector(31 downto 0);
        variable temp_mem : mem_type := (others => (others => '0'));
        variable i : integer := 0;
    begin
        -- Try opening the file normally
        file_open(status, text_file, filename, read_mode);

        -- If failed, try looking one directory up (common in ModelSim)
        if status /= open_ok then
            file_open(status, text_file, "../" & filename, read_mode);
        end if;

        -- If failed, try looking two directories up
        if status /= open_ok then
            file_open(status, text_file, "../../" & filename, read_mode);
        end if;

        -- FINAL FALLBACK: Try the absolute path on the original machine
        -- This helps if the simulation is running in a completely different folder
        if status /= open_ok then
            file_open(status, text_file, "C:/Users/mohse/pipelord/" & filename, read_mode);
        end if;

        -- If still failed, crash with a helpful message
        if status /= open_ok then
            report "Error: Could not open memory initialization file: " & filename & 
                   ". Checked ./, ../, ../../, and C:/Users/mohse/pipelord/. Please ensure '" & filename & "' is in your simulation directory." severity failure;
            return temp_mem;
        end if;

        while not endfile(text_file) and i < 2**18 loop
            readline(text_file, text_line);
            read(text_line, temp_bv);
            temp_mem(i) := to_stdlogicvector(temp_bv);
            i := i + 1;
        end loop;

        file_close(text_file);
        return temp_mem;
    end function;

    -- Initialize memory using generic parameter
    signal ram : mem_type := init_mem(INIT_FILE);

begin

    process(clk)
    begin
        if rising_edge(clk) then
            if we = '1' then
                ram(to_integer(unsigned(address(17 downto 0)))) <= datain;
            end if;
        end if;
    end process;

    dataout <= ram(to_integer(unsigned(address(17 downto 0)))) when re = '1' else (others => '0');

end Behavioral;

