USE IEEE.NUMERIC_STD.ALL;

ENTITY SP_module IS
    GENERIC (
        WIDTH : NATURAL := 32;
        RESET_VALUE : STD_LOGIC_VECTOR(31 DOWNTO 0) := (OTHERS => '1') -- Default reset value (0xFFFFFFFF)
    );
    PORT (
        clk         : IN STD_LOGIC;
        rst         : IN STD_LOGIC;
        en_sp       : IN STD_LOGIC;                     -- Enable signal for SP update
        inc_sp      : IN STD_LOGIC;                     -- 1=Increment, 0=Decrement
        use_old_sp  : IN STD_LOGIC;                     -- 1=Output Old Value, 0=Output New Value
        sp_out      : OUT STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0) -- Selected SP value
    );
END SP_module;

ARCHITECTURE SP_module_arch OF SP_module IS
    -- Internal signals
    SIGNAL sp_current : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Current SP register value
    SIGNAL sp_new     : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- New SP after add_sub operation

BEGIN
    -- Adder/Subtractor Logic
    PROCESS(sp_current, inc_sp)
    BEGIN
        IF inc_sp = '1' THEN
            sp_new <= std_logic_vector(unsigned(sp_current) + 1);
        ELSE
            sp_new <= std_logic_vector(unsigned(sp_current) - 1);
        END IF;
    END PROCESS;

    -- SP Register Process
    sp_register: PROCESS(clk, rst)
    BEGIN
        IF rst = '1' THEN
            sp_current <= RESET_VALUE;
        ELSIF rising_edge(clk) THEN
            IF en_sp = '1' THEN
                sp_current <= sp_new;
            END IF;
        END IF;
    END PROCESS;

    -- Mux: Selects between old SP (current) and new SP
    sp_out <= sp_current WHEN use_old_sp = '1' ELSE sp_new;

END SP_module_arch;

