            clk         : IN STD_LOGIC;
            rst         : IN STD_LOGIC;
            en_sp       : IN STD_LOGIC;
            inc_sp      : IN STD_LOGIC;
            use_old_sp  : IN STD_LOGIC;
            sp_out      : OUT STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0)
        );
    END COMPONENT;

    COMPONENT mux2to1_N IS
        GENERIC (
            WIDTH : NATURAL := 32
        );
        PORT (
            d0  : IN STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0);
            d1  : IN STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0);
            sel : IN STD_LOGIC;
            y   : OUT STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0)
        );
    END COMPONENT;

    SIGNAL sp_output : STD_LOGIC_VECTOR(WIDTH-1 DOWNTO 0); -- Output from SP module

BEGIN
    -- SP Module Instance
    sp_unit: SP_module
        GENERIC MAP (
            WIDTH => WIDTH,
            RESET_VALUE => SP_RESET_VALUE
        )
        PORT MAP (
            clk        => clk,
            rst        => rst,
            en_sp      => en_sp,
            inc_sp     => inc_sp,
            use_old_sp => use_old_sp,
            sp_out     => sp_output
        );

    -- Memory Address MUX (selects between ALU result and SP output)
    mem_add_mux: mux2to1_N
        GENERIC MAP (
            WIDTH => WIDTH
        )
        PORT MAP (
            d0  => ALU_result,  -- 0: ALU result
            d1  => sp_output,   -- 1: SP output
            sel => use_sp_add,
            y   => mem_address
        );

    -- [ADDED FIX 1] Send Store Data to RAM
    mem_wr_data <= write_data_in;

    -- [ADDED FIX 2] Send ALU Result to WB (bypass memory)
    alu_result_out <= ALU_result;

    -- Pass-through assignments for data
    mem_data_out   <= mem_data_in;   -- Memory data from Von-Neumann memory
    write_data_out <= write_data_in; -- Write data pass-through
    r1_out         <= r1_in;         -- R1 pass-through
    r3_out         <= r3_in;         -- R3 pass-through

    -- Pass-through for control signals
    mem_read_out         <= mem_read;
    mem_write_out        <= mem_write;
    Load_PC_From_Mem_out <= Load_PC_From_Mem_in;
    Mem_Add_Src_out      <= Mem_Add_Src_in;

    is_swap_out          <= is_swap;
    mem_to_reg_wb_out    <= mem_to_reg_wb;
    reg_write_en_out     <= reg_write_en;

END memory_stage_arch;
